mapper.select:
select a.*,c.* from email_push_main a
INNER JOIN (
SELECT main_id,
count(*) AS totalSentCount,
COALESCE(SUM(CASE WHEN is_send = 1 THEN 1 ELSE 0 END), 0) AS actualSentCount,
COALESCE(SUM(CASE WHEN is_send = -1 THEN 1 ELSE 0 END), 0) AS bounceCount,
COALESCE ( SUM( CASE WHEN is_opened = 1 THEN 1 ELSE 0 END ), 0 ) AS openCount,
COALESCE ( SUM( CASE WHEN is_reply = 1 THEN 1 ELSE 0 END ), 0 ) AS replyCount
FROM email_push_detail
GROUP BY main_id
) c ON a.id = c.main_id


        and a.business_type = #{emailPushMain.businessType}


        and a.signature_id = #{emailPushMain.signatureId}


        and a.brand_id = #{emailPushMain.brandId}


        and a.product_id = #{emailPushMain.productId}


        and a.contact_email_id = #{emailPushMain.contactEmailId}


        and counselor_id = #{emailPushMain.counselorId}


        and cc_emails = #{emailPushMain.ccEmails}


        and email_push_date >= #{emailPushMain.emailPushDateStart}


        and email_push_date <= #{emailPushMain.emailPushDateEnd}

    AND EXISTS (
    SELECT 1
    FROM email_push_detail d
    WHERE d.main_id = a.id

        AND d.username LIKE CONCAT('%', #{emailPushMain.username}, '%')


        AND d.email LIKE CONCAT('%', #{emailPushMain.email}, '%')


        AND d.is_reply = #{emailPushMain.isReply}


        AND d.is_send = #{emailPushMain.isSend}


        AND d.brand_category_id = #{emailPushMain.brandCategoryId}

    )

order by create_time desc
